import numpy as npdef generate_synthetic_data(num_sequences=3, samples_per_sequence=100,                             sequence_length=7, num_actions=4, add_input_noise=False):    """    Purpose:        - Generate synthetic motor sequence learning data, for both pre-train and RP IP training    Parameters:        - num_sequences = the number of tasks being learned (here 3)        - samples_per_sequence = amount of practices per task (here 5000)        - sequence_length = number of motor actions made per task (here 7)        - num_actions = number of actions to choose from (here 4 fingers)        - add_input_noise = add Gaussian noise to input, simulate environmental noise        We create:        - Multiple distinct sequences (tasks)        - Repeat each sequence many times (practice)        - Return two versions:            1. Blocked for RP sequences grouped together            2. Interleaved for IP: sequences randomly mixed    Outputs:        - blocked_inputs: data ordered by sequence (RP condition)        - blocked_targets: corresponding one-hot labels        - interleaved_inputs: same data but shuffled (IP condition)        - interleaved_targets: shuffled labels    Output Shapes:        - Inputs: (num_sequences * samples_per_sequence, 1, sequence_length)        - Targets: (num_sequences * samples_per_sequence, sequence_length, num_actions)    """    # dummy containers    all_inputs = []    all_targets = []    # (1) Generate distinct sequences and their corresponding targets    for i in range(num_sequences):        # create 1 sequence of 7 integers, representing motor actions (0,1,2,3)        base_sequence = np.random.randint(low=0,high=num_actions,size=(sequence_length,))        # transform to one-hot targets        # example: action = 3-1 = 2 = [0,0,1,0]        one_hot_targets = np.zeros((sequence_length, num_actions))        for t in range(sequence_length):            action = base_sequence[t] # grab action number            one_hot_targets[t, action] = 1 # set to 1        # repeat the sequence        repeated_inputs = np.tile(base_sequence, (samples_per_sequence, 1))        repeated_inputs = repeated_inputs[:, np.newaxis, :] # reshape to match RNN format        repeated_targets = np.tile(one_hot_targets, (samples_per_sequence, 1, 1))        # store        all_inputs.append(repeated_inputs)        all_targets.append(repeated_targets)    # (2) Combine sequences in repetitive format (AAA BBB CCC)    repetitive_inputs = np.concatenate(all_inputs, axis=0)    repetitive_targets = np.concatenate(all_targets, axis=0)    # shift to match original behavior    repetitive_inputs = repetitive_inputs + 1    # (3) Add noise to input sequences: avoid overfitting    if add_input_noise:        # change int32 to float64        repetitive_inputs = repetitive_inputs.astype(np.float64)        # add Gaussian noise with mean=0, sd=0.1        noise = np.random.normal(0, 0.1, repetitive_inputs.shape)        repetitive_inputs += noise    # (4) Create the interleaved version for IP    interleaved_inputs = repetitive_inputs.copy()    interleaved_targets = repetitive_targets.copy()    # random reordering of rows: ABC BCA CAB...     shuffle_indices = np.random.permutation(interleaved_inputs.shape[0])    interleaved_inputs = interleaved_inputs[shuffle_indices]    interleaved_targets = interleaved_targets[shuffle_indices]    return repetitive_inputs, repetitive_targets, interleaved_inputs, interleaved_targets    """    Generate Replay Data:            The X_repetitive and y_reletitive datasets looks like:        [5000 A | 5000 B | 5000 C], A B C are 3 task sequences    In the replay dataset, we randomly select 150 sequences from each block    to mimic limited replay during sleeping in human and avoid overfitting;    The concatenated dataset will then be shuffled,     """def sample_balanced_replay(X, y, num_per_seq=5000, k=150):        X_A = X[:num_per_seq]    y_A = y[:num_per_seq]    X_B = X[num_per_seq:2*num_per_seq]    y_B = y[num_per_seq:2*num_per_seq]    X_C = X[2*num_per_seq:3*num_per_seq]    y_C = y[2*num_per_seq:3*num_per_seq]    idx_A = np.random.choice(num_per_seq, size=k, replace=False)    idx_B = np.random.choice(num_per_seq, size=k, replace=False)    idx_C = np.random.choice(num_per_seq, size=k, replace=False)    X_replay = np.concatenate([        X_A[idx_A],        X_B[idx_B],        X_C[idx_C]    ], axis=0)    y_replay = np.concatenate([        y_A[idx_A],        y_B[idx_B],        y_C[idx_C]    ], axis=0)    perm = np.random.permutation(len(X_replay))    return X_replay[perm], y_replay[perm]"""The following function generates selected replay dataset for RP model"""def sample_selected_replay(X, y, num_per_seq=5000, k_A=200, k_B=180, k_C=70):        X_A = X[:num_per_seq]    y_A = y[:num_per_seq]    X_B = X[num_per_seq:2*num_per_seq]    y_B = y[num_per_seq:2*num_per_seq]    X_C = X[2*num_per_seq:3*num_per_seq]    y_C = y[2*num_per_seq:3*num_per_seq]    idx_A = np.random.choice(num_per_seq, size=k_A, replace=False)    idx_B = np.random.choice(num_per_seq, size=k_B, replace=False)    idx_C = np.random.choice(num_per_seq, size=k_C, replace=False)    X_replay = np.concatenate([        X_A[idx_A],        X_B[idx_B],        X_C[idx_C]    ], axis=0)    y_replay = np.concatenate([        y_A[idx_A],        y_B[idx_B],        y_C[idx_C]    ], axis=0)    perm = np.random.permutation(len(X_replay))    return X_replay[perm], y_replay[perm]